  if (typeof value === "object" && value !== null) {
    return jsonLikeRecord(value as Record<string, unknown>);
  }

  if (
    value === null ||
    typeof value === "boolean" ||
    typeof value === "number" ||
    typeof value === "string" ||
    typeof value === "bigint" ||
    value instanceof Uint8Array
  ) {
